225	function normalizeTelegramAcpConversationId(conversationId: string) {
226	  const parsed = parseTelegramTopicConversation({ conversationId });
227	  if (!parsed || !parsed.chatId.startsWith("-")) {
228	    return null;
229	  }
230	  return {
231	    conversationId: parsed.canonicalConversationId,
232	    parentConversationId: parsed.chatId,
233	  };
234	}
