292	function parseTelegramExplicitTarget(raw: string) {
293	  const target = parseTelegramTarget(raw);
294	  return {
295	    to: target.chatId,
296	    threadId: target.messageThreadId,
297	    chatType: target.chatType === "unknown" ? undefined : target.chatType,
298	  };
299	}
