301	function buildTelegramBaseSessionKey(params: {
302	  cfg: OpenClawConfig;
303	  agentId: string;
304	  accountId?: string | null;
305	  peer: RoutePeer;
306	}) {
307	  return buildOutboundBaseSessionKey({ ...params, channel: "telegram" });
