457	export const telegramPlugin = createChatChannelPlugin({
458	  base: {
459	    ...createTelegramPluginBase({
460	      setupWizard: telegramSetupWizard,
461	      setup: telegramSetupAdapter,
462	    }),
463	    allowlist: buildDmGroupAccountAllowlistAdapter({
464	      channelId: "telegram",
465	      resolveAccount: resolveTelegramAccount,
466	      normalize: ({ cfg, accountId, values }) =>
467	        telegramConfigAdapter.formatAllowFrom!({ cfg, accountId, allowFrom: values }),
468	      resolveDmAllowFrom: (account) => account.config.allowFrom,
469	      resolveGroupAllowFrom: (account) => account.config.groupAllowFrom,
470	      resolveDmPolicy: (account) => account.config.dmPolicy,
471	      resolveGroupPolicy: (account) => account.config.groupPolicy,
472	      resolveGroupOverrides: resolveTelegramAllowlistGroupOverrides,
473	    }),
474	    bindings: {
475	      compileConfiguredBinding: ({ conversationId }) =>
476	        normalizeTelegramAcpConversationId(conversationId),
477	      matchInboundConversation: ({ compiledBinding, conversationId, parentConversationId }) =>
478	        matchTelegramAcpConversation({
479	          bindingConversationId: compiledBinding.conversationId,
480	          conversationId,
481	          parentConversationId,
482	        }),
483	      resolveCommandConversation: ({ threadId, originatingTo, commandTo, fallbackTo }) =>
484	        resolveTelegramCommandConversation({
485	          threadId,
486	          originatingTo,
487	          commandTo,
488	          fallbackTo,
489	        }),
490	    },
491	    conversationBindings: {
492	      supportsCurrentConversationBinding: true,
493	      createManager: ({ accountId }) =>
494	        createTelegramThreadBindingManager({
495	          accountId: accountId ?? undefined,
496	          persist: false,
497	          enableSweeper: false,
498	        }),
499	      setIdleTimeoutBySessionKey: ({ targetSessionKey, accountId, idleTimeoutMs }) =>
500	        setTelegramThreadBindingIdleTimeoutBySessionKey({
501	          targetSessionKey,
502	          accountId: accountId ?? undefined,
503	          idleTimeoutMs,
504	        }),
505	      setMaxAgeBySessionKey: ({ targetSessionKey, accountId, maxAgeMs }) =>
506	        setTelegramThreadBindingMaxAgeBySessionKey({
507	          targetSessionKey,
508	          accountId: accountId ?? undefined,
509	          maxAgeMs,
510	        }),
511	    },
512	    groups: {
513	      resolveRequireMention: resolveTelegramGroupRequireMention,
514	      resolveToolPolicy: resolveTelegramGroupToolPolicy,
515	    },
516	    agentPrompt: {
517	      messageToolCapabilities: ({ cfg, accountId }) => {
518	        const inlineButtonsScope = resolveTelegramInlineButtonsScope({
519	          cfg,
520	          accountId: accountId ?? undefined,
521	        });
522	        return inlineButtonsScope === "off" ? [] : ["inlineButtons"];
523	      },
524	      reactionGuidance: ({ cfg, accountId }) => {
525	        const level = resolveTelegramReactionLevel({
526	          cfg,
527	          accountId: accountId ?? undefined,
528	        }).agentReactionGuidance;
529	        return level ? { level, channelLabel: "Telegram" } : undefined;
530	      },
531	    },
532	    messaging: {
533	      normalizeTarget: normalizeTelegramMessagingTarget,
534	      resolveSessionConversation: ({ kind, rawId }) =>
535	        resolveTelegramSessionConversation({ kind, rawId }),
536	      parseExplicitTarget: ({ raw }) => parseTelegramExplicitTarget(raw),
537	      inferTargetChatType: ({ to }) => parseTelegramExplicitTarget(to).chatType,
538	      formatTargetDisplay: ({ target, display, kind }) => {
539	        const formatted = display?.trim();
540	        if (formatted) {
541	          return formatted;
542	        }
543	        const trimmedTarget = target.trim();
544	        if (!trimmedTarget) {
545	          return trimmedTarget;
546	        }
547	        const withoutProvider = trimmedTarget.replace(/^(telegram|tg):/i, "");
548	        if (kind === "user" || /^user:/i.test(withoutProvider)) {
549	          return `@${withoutProvider.replace(/^user:/i, "")}`;
550	        }
551	        if (/^channel:/i.test(withoutProvider)) {
552	          return `#${withoutProvider.replace(/^channel:/i, "")}`;
553	        }
