222	            return {
223	              input,
224	              resolved: false,
225	              note: "invalid IRC target",
226	            };
227	          }
228	          if (kind === "group") {
229	            const groupId = isChannelTarget(normalized) ? normalized : `#${normalized}`;
230	            return {
231	              input,
232	              resolved: true,
233	              id: groupId,
234	              name: groupId,
235	            };
236	          }
237	          if (isChannelTarget(normalized)) {
238	            return {
239	              input,
240	              resolved: false,
241	              note: "expected user target",
242	            };
243	          }
