130	export function normalizeChatChannelId(raw?: string | null): ChatChannelId | null {
131	  const normalized = normalizeChannelKey(raw);
132	  if (!normalized) {
133	    return null;
134	  }
135	  const resolved = CHAT_CHANNEL_ALIASES[normalized] ?? normalized;
136	  return CHAT_CHANNEL_ORDER.includes(resolved) ? resolved : null;
