432	        cfg,
433	        channel: "nostr",
434	        accountId: aid,
435	      });
436	      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
437	      const normalizedTo = normalizePubkey(to);
438	      await bus.sendDm(normalizedTo, message);
439	      return attachChannelToResult("nostr", {
440	        to: normalizedTo,
441	        messageId: `nostr-${Date.now()}`,
442	      });
443	    },
444	  },
445	});
