import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  createChatChannelPlugin,
  getChatChannelMeta,
  type ChannelPlugin,
} from "openclaw/plugin-sdk/core";

type PulseBoardChannelMeta = Parameters<typeof getChatChannelMeta>[0];

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
      order: 200,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => ["default"],
      resolveAccount: () => ({
        accountId: "default",
        name: "default",
        enabled: true,
        configured: false,
      }),
      defaultAccountId: () => "default",
      isConfigured: (account: { configured?: boolean }) => account.configured ?? false,
      describeAccount: (account: { accountId?: string }) => ({
        accountId: account.accountId ?? "default",
        configured: false,
      }),
    },
    setup: {
      applyAccountConfig: async () => {},
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.account.accountId ?? "default"}] starting PulseBoard provider`,
        );
      },
    },
    messaging: {
      normalizeTarget: (target: string) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

